def ensure_parent(path: Path):
    path.parent.mkdir(parents=True, exist_ok=True)

def backup(path: Path):
    if path.exists():
        dest = BACKUP_DIR / path
        ensure_parent(dest)
        shutil.copy2(path, dest)

def write_file(path_str: str, content: str):
    path = ROOT / path_str
    # backup skipped because Windows/OneDrive locked a file
    ensure_parent(path)
    path.write_text(content, encoding="utf-8")
    print(f"wrote {path_str}")

def update_package_script():
    pkg_path = ROOT / "package.json"
    if not pkg_path.exists():
        return
    backup(pkg_path)
    try:
        pkg = json.loads(pkg_path.read_text(encoding="utf-8"))
    except Exception:
        print("package.json could not be parsed; skipping script update.")
        return
    scripts = pkg.setdefault("scripts", {})
    scripts.setdefault("health:db", "node scripts/check-database-health.cjs")
    pkg_path.write_text(json.dumps(pkg, indent=2) + "\n", encoding="utf-8")
    print("updated package.json with health:db script")

for path_str, content in FILES.items():
    write_file(path_str, content)

update_package_script()

print("\nDone. Backups were saved to:", BACKUP_DIR)
print("Next commands:")
print("  rm -rf .next")
print("  npx prisma generate")
print("  npm run dev")
print("Then open: http://localhost:3000/admin/health")
